def solve(landStartTime: Array[Long], landDuration: Array[Long], waterStartTime: Array[Long], waterDuration: Array[Long]): Long = {
  var minTime = Long.MaxValue
  for (i <- 0 until landStartTime.length) {
    for (j <- 0 until waterStartTime.length) {
      // Calculate time when land is first
      val landEnd = landStartTime(i) + landDuration(i)
      val waterStart = math.max(landEnd, waterStartTime(j))
      val waterEnd = waterStart + waterDuration(j)
      val case1 = waterEnd

      // Calculate time when water is first
      val waterEnd2 = waterStartTime(j) + waterDuration(j)
      val landStart = math.max(waterEnd2, landStartTime(i))
      val landEnd2 = landStart + landDuration(i)
      val case2 = landEnd2

      val currentMin = math.min(case1, case2)
      if (currentMin < minTime) {
        minTime = currentMin
      }
    }
  }
  minTime
}
